import{_ as t,o,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Target Operating Model","description":"","frontmatter":{},"headers":[],"relativePath":"development/operating-model.md","filePath":"development/operating-model.md","lastUpdated":1775719799000}'),d={name:"development/operating-model.md"};function i(n,e,l,s,c,p){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="target-operating-model" tabindex="-1">Target Operating Model <a class="header-anchor" href="#target-operating-model" aria-label="Permalink to &quot;Target Operating Model&quot;">​</a></h1><p><strong>Last updated:</strong> 2026-03-22 <strong>Reference:</strong> LLM Development Operating Model v2.0</p><hr><h2 id="_1-goal" tabindex="-1">1. Goal <a class="header-anchor" href="#_1-goal" aria-label="Permalink to &quot;1. Goal&quot;">​</a></h2><p>rustchat aims to be a <strong>production-ready, self-hosted team collaboration server</strong> that:</p><ol><li>Is <strong>fully Mattermost-compatible</strong> for mobile and desktop clients (target: 41/41; currently 39/41 — see Section 3)</li><li>Is <strong>safe to develop with LLM agents</strong> — every area has clear ownership, risk classification, and scope boundaries</li><li>Has <strong>high test confidence</strong> — elevated and architectural changes require mandatory test coverage</li><li>Supports <strong>horizontal scaling</strong> — stateless API servers, Redis pub/sub, connection pooling</li></ol><hr><h2 id="_2-operating-model-applied" tabindex="-1">2. Operating Model Applied <a class="header-anchor" href="#_2-operating-model-applied" aria-label="Permalink to &quot;2. Operating Model Applied&quot;">​</a></h2><p>The LLM Development Operating Model v2.0 is being applied to rustchat in phases:</p><table tabindex="0"><thead><tr><th>Phase</th><th>Description</th><th>Status</th></tr></thead><tbody><tr><td>Governance layer</td><td><code>.governance/</code> policy files, CODEOWNERS, PR template, issue forms, branch protection, GitHub labels</td><td>✅ Complete (2026-03-22)</td></tr><tr><td>Foundation docs</td><td>7 structured docs: architecture, agent model, compat scope, testing, ownership, repo state, target model</td><td>✅ Complete (2026-03-22)</td></tr><tr><td>CI enforcement (Approach C)</td><td>Automated PR policy checks, agent boundary enforcement, label validation</td><td>🔲 Deferred</td></tr><tr><td>Incident readiness</td><td>Revert policy, hotfix process, post-mortem template, dependency vulnerability SLA</td><td>🔲 Deferred</td></tr><tr><td>Remaining foundation docs</td><td><code>migration-roadmap.md</code>, <code>release-model.md</code>, <code>dependency-policy.md</code></td><td>🔲 Deferred</td></tr></tbody></table><hr><h2 id="_3-compatibility-target" tabindex="-1">3. Compatibility Target <a class="header-anchor" href="#_3-compatibility-target" aria-label="Permalink to &quot;3. Compatibility Target&quot;">​</a></h2><p><strong>Current:</strong> 39/41 mobile-critical endpoints (95.1%)</p><p><strong>Target:</strong> 41/41 mobile endpoints + verified desktop client support</p><p><strong>Gap to close:</strong></p><ul><li><code>POST /api/v4/emoji</code> — custom emoji upload (Phase 2)</li><li><code>POST /api/v4/posts/search</code> — advanced search (Phase 2)</li></ul><hr><h2 id="_4-agent-workflow-target" tabindex="-1">4. Agent Workflow Target <a class="header-anchor" href="#_4-agent-workflow-target" aria-label="Permalink to &quot;4. Agent Workflow Target&quot;">​</a></h2><p>All agent-driven development follows:</p><ul><li>Spec → plan → subagent execution → two-stage review (spec compliance + code quality) → PR</li><li>No direct commits to protected paths without prior spec</li><li>compat-agent produces analysis artifacts only; production code written by backend-agent with compat-reviewer co-approval</li></ul><p>This is enforced by convention today (<code>.governance/agent-contracts.yml</code>). Approach C will add automated CI enforcement.</p><hr><h2 id="_5-deferred-items" tabindex="-1">5. Deferred Items <a class="header-anchor" href="#_5-deferred-items" aria-label="Permalink to &quot;5. Deferred Items&quot;">​</a></h2><p>The following are explicitly out of scope until a future phase:</p><table tabindex="0"><thead><tr><th>Item</th><th>Reason deferred</th></tr></thead><tbody><tr><td>Approach C (CI enforcement workflows)</td><td>Requires stable policy files first; enforcement added after contracts prove out</td></tr><tr><td><code>docs/migration-roadmap.md</code></td><td>Requires Phase 2 scope to be defined first</td></tr><tr><td><code>docs/release-model.md</code></td><td>Current release process is documented in <code>bump-version.sh</code>; formal doc deferred</td></tr><tr><td><code>docs/dependency-policy.md</code></td><td>No Dependabot yet; doc deferred until automation is in place</td></tr><tr><td>Incident readiness docs</td><td>Low priority until production deployment</td></tr></tbody></table>',25)])])}const g=t(d,[["render",i]]);export{h as __pageData,g as default};
